// STEP 1: WORLD_INGEST — gather world events since last tick
// In production, this would poll external APIs, news feeds, message queues, etc.

let state = $getWorkflowStaticData('global').agentState;
if (!state) {
  // No state yet — skip this tick
  return [{ json: { skip: true, reason: 'No agent state initialized. Run Interaction Cycle first.' } }];
}

state.tick_counter = (state.tick_counter || 0) + 1;

// Collect any world events (placeholder — integrate your event sources)
const worldEvents = [];

// Check for any user interactions since last tick
const episodicLog = $getWorkflowStaticData('global').episodicLog || [];
const lastTickTime = $getWorkflowStaticData('global').lastFastTick || 0;
const now = Date.now();

const recentInteractions = episodicLog.filter(e => {
  const t = new Date(e.created_at).getTime();
  return t > lastTickTime && e.type === 'user_interaction';
});

if (recentInteractions.length > 0) {
  worldEvents.push({ type: 'conversation', source: 'user_interaction', count: recentInteractions.length });
}

$getWorkflowStaticData('global').lastFastTick = now;

return [{
  json: {
    state,
    world_events: worldEvents,
    activity_events: worldEvents,
    cycle_id: `fast-${state.tick_counter}`,
    cycle_type: 'fast_tick',
    timestamp: new Date().toISOString()
  }
}];

// STEP 2: APPRAISE — evaluate world events against goals/values
const item = $input.first().json;
const state = item.state;
const worldEvents = item.world_events || [];

const appraisals = [];
for (const event of worldEvents) {
  let goalCongruence = 0;
  let threat = 0;
  let arousalCue = 0;

  // Events that progress goals are positively appraised
  if (event.type === 'conversation') {
    goalCongruence = 0.2;
    arousalCue = 0.1;
  } else if (event.type === 'goal_progress') {
    goalCongruence = 0.4;
    arousalCue = 0.2;
  } else if (event.type === 'threat' || event.type === 'conflict') {
    threat = 0.3;
    arousalCue = 0.3;
  }

  appraisals.push({ goal_congruence: goalCongruence, threat, arousal_cue: arousalCue, source_event: event.type });
}

return [{ json: { ...item, appraisals } }];

// STEP 3: UPDATE_EMOTION — EMA-based affect update
const item = $input.first().json;
const state = item.state;
const appraisals = item.appraisals || [];
const tick = state.tick_counter || 0;

function ema(v, b, r) { return v + (b - v) * r; }
function clamp(v, lo = -1, hi = 1) { return Math.max(lo, Math.min(hi, v)); }

const baseline = { valence: 0.10, arousal: 0.30, stress: 0.10, energy: 0.70 };
const decay = { valence: 0.05, arousal: 0.08, stress: 0.06, energy: 0.04 };

// 1. EMA decay
let valence = ema(state.affect.valence, baseline.valence, decay.valence);
let arousal = ema(state.affect.arousal, baseline.arousal, decay.arousal);
let stress = ema(state.affect.stress, baseline.stress, decay.stress);
let energy = ema(state.affect.energy, baseline.energy, decay.energy);

// 2. Circadian modulation
const ticksPerDay = 48; // 30-min intervals
const amplitude = 0.15;
const peakTick = 10 * 2; // hour 10 * 2 ticks/hour
const phase = (2 * Math.PI * ((tick % ticksPerDay) - peakTick)) / ticksPerDay;
energy += amplitude * Math.cos(phase);

// 3. Appraisal deltas
for (const a of appraisals) {
  valence += (a.goal_congruence || 0) * 0.10;
  stress += (a.threat || 0) * 0.10;
  arousal += (a.arousal_cue || 0) * 0.05;
}

state.affect = {
  valence: clamp(valence), arousal: clamp(arousal),
  stress: clamp(stress), energy: clamp(energy)
};

// Stress → rest coupling
const restBoost = stress > 0.70 ? 0.01 : 0.0;

return [{ json: { ...item, state, _rest_boost: restBoost } }];

// STEP 4: UPDATE_DRIVES — growth, satisfaction, and stress coupling
const item = $input.first().json;
const state = item.state;
const activityEvents = item.activity_events || [];
const restBoost = item._rest_boost || 0.0;

const DRIVE_NAMES = ['social_need', 'mastery_need', 'rest_need', 'curiosity'];
const growthRates = { social_need: 0.04, mastery_need: 0.02, rest_need: 0.03, curiosity: 0.01 };
const satisfactionMap = {
  social_need: { satisfied_by: ['conversation', 'social_activity', 'group_event'], reduction: 0.25 },
  mastery_need: { satisfied_by: ['goal_progress', 'task_completion', 'learning_episode'], reduction: 0.20 },
  rest_need: { satisfied_by: ['sleep', 'low_arousal_idle_period'], reduction: 0.40 },
  curiosity: { satisfied_by: ['reading', 'exploring_topic', 'creative_activity'], reduction: 0.30 }
};

const drives = { ...state.drives };

// Growth
for (const d of DRIVE_NAMES) drives[d] += growthRates[d] || 0;
drives.rest_need += restBoost;

// Satisfaction
const eventTypes = activityEvents.map(e => e.type || '');
for (const d of DRIVE_NAMES) {
  const sat = satisfactionMap[d];
  if (!sat) continue;
  for (const t of eventTypes) {
    if (sat.satisfied_by.includes(t)) drives[d] -= sat.reduction;
  }
}

// Clamp
for (const d of DRIVE_NAMES) drives[d] = Math.max(0, Math.min(1, drives[d]));

state.drives = drives;
return [{ json: { ...item, state } }];

// STEP 5: GENERATE_THOUGHT — produce one thought fragment per tick
const item = $input.first().json;
const state = item.state;
const tick = state.tick_counter || 0;

const CATEGORIES = ['reflection', 'planning', 'rumination', 'curiosity', 'self-evaluation', 'social', 'fantasy'];

const templates = {
  reflection: ['Thinking about what matters most right now.', 'Sitting with a quiet sense of what today has been.', 'Noticing patterns in how things have been going lately.', 'Wondering what I make of recent events.'],
  planning: ['Thinking through what needs to happen next.', 'Mapping out steps to move something forward.', 'Weighing different approaches to a current challenge.', 'Imagining what progress would look like.'],
  rumination: ['Turning something difficult over in my mind again.', 'Finding it hard to set aside what\'s been bothering me.', 'Dwelling on something that didn\'t go the way I hoped.', 'Replaying a moment that still feels unresolved.'],
  curiosity: ['Wondering about something I don\'t fully understand yet.', 'Feeling pulled toward a question I haven\'t explored.', 'Noticing an interesting idea I\'d like to think through.', 'Something unfamiliar has caught my attention.'],
  'self-evaluation': ['Asking myself whether I\'m living up to what I care about.', 'Reconsidering how I handled something recently.', 'Checking in with whether I\'m on the right track.', 'Wondering if I could do better in some area.'],
  social: ['Thinking about someone I\'d like to reach out to.', 'Remembering a recent exchange that stayed with me.', 'Wondering how someone I care about is doing.', 'Feeling the pull of wanting to connect.'],
  fantasy: ['Imagining a quiet, low-demand stretch of time.', 'Daydreaming about stepping back from everything for a bit.', 'Picturing a simpler moment without any pressing demands.', 'Wishing for a slower pace, at least for now.']
};

// Category selection based on affect/drives
let category = 'reflection';
const { affect, drives } = state;
if (affect.valence < -0.3) {
  category = drives.mastery_need > 0.4 ? 'self-evaluation' : 'rumination';
} else if (affect.arousal > 0.6) {
  category = drives.curiosity > drives.mastery_need ? 'curiosity' : 'planning';
} else if (drives.social_need > 0.5) {
  category = 'social';
}

// Guardrail: no more than 3 consecutive same category
const recent = state.consecutive_thought_categories || [];
if (recent.length >= 3 && recent.slice(-3).every(c => c === category)) {
  category = CATEGORIES.find(c => c !== category) || 'reflection';
}

const text = templates[category][tick % templates[category].length];

// Track consecutive categories (cap at 3)
const updatedRecent = [...recent, category].slice(-3);
state.consecutive_thought_categories = updatedRecent;

const thought = {
  id: `thought-${tick}-${Date.now()}`,
  text,
  thought_category: category,
  trigger: 'internal',
  intrusiveness: Math.min(1.0, 0.3 + Math.abs(affect.valence - 0.1) * 0.3),
  created_at: new Date().toISOString()
};

return [{ json: { ...item, state, thought } }];

// STEP 6: SALIENCE_FILTER — lightweight salience check for tick
const item = $input.first().json;
const state = item.state;

// In fast tick, salience filtering is simpler than interaction cycle
// Just note the thought as current focus
state.attention = {
  current_focus: item.thought?.thought_category || null,
  salience_buffer: state.attention?.salience_buffer || []
};

return [{ json: { ...item, state } }];

// STEP 7: UPDATE_GOALS — tick goal progress and frustration
const item = $input.first().json;
const state = item.state;

const suspensionThreshold = 0.75;
const frustrationGrowth = 0.05;
const frustrationDecay = 0.10;

state.goals = (state.goals || []).map(goal => {
  if (goal.status !== 'active') return goal;

  const stalled = (goal.blocked_by || []).length > 0;
  let progress = goal.progress;
  let frustration = goal.frustration;
  let status = goal.status;

  if (stalled) {
    frustration = Math.min(1.0, frustration + frustrationGrowth);
  } else {
    progress = Math.min(1.0, progress + 0.01);
    frustration = Math.max(0.0, frustration - frustrationDecay);
  }

  if (frustration >= suspensionThreshold) status = 'suspended';

  return { ...goal, progress: Math.round(progress * 10000) / 10000, frustration: Math.round(frustration * 10000) / 10000, status };
});

return [{ json: { ...item, state } }];

// STEP 8: WRITE_MEMORY — persist thought as episodic event
const item = $input.first().json;
const state = item.state;
const thought = item.thought;

if (thought) {
  const episodicLog = $getWorkflowStaticData('global').episodicLog || [];
  episodicLog.push({
    id: thought.id,
    type: 'thought',
    text: thought.text,
    thought_category: thought.thought_category,
    importance: thought.intrusiveness * 0.5,
    similarity: 0,
    recency: 1.0,
    self_relevance: 0.2,
    created_at: thought.created_at,
    lifecycle_state: 'active',
    affect_snapshot: { ...state.affect },
    drive_snapshot: { ...state.drives }
  });

  // Cap episodic log size
  if (episodicLog.length > 200) episodicLog.splice(0, episodicLog.length - 200);
  $getWorkflowStaticData('global').episodicLog = episodicLog;
}

// Persist updated state
$getWorkflowStaticData('global').agentState = state;

// Clear ephemeral
state.attention = { current_focus: null, salience_buffer: [] };
state.active_desires = [];

return [{
  json: {
    cycle_id: item.cycle_id,
    cycle_type: 'fast_tick',
    tick_counter: state.tick_counter,
    thought_category: thought?.thought_category,
    affect: state.affect,
    drives: state.drives,
    active_goals: state.goals.filter(g => g.status === 'active').length,
    timestamp: new Date().toISOString()
  }
}];
